import{c as l,Z as e,Q as t,j as o,g as n,n as a,o as i,m as r}from"./chunks/framework.qjzPVSkb.js";const v=JSON.parse('{"title":"角色扮演类模板","description":"面试模拟、场景对话、头脑风暴、代码评审——让 AI 扮演专业角色来提升交互质量","frontmatter":{"title":"角色扮演类模板","description":"面试模拟、场景对话、头脑风暴、代码评审——让 AI 扮演专业角色来提升交互质量","difficulty":"beginner"},"headers":[],"relativePath":"prompts/roleplay.md","filePath":"prompts/roleplay.md"}'),c={name:"prompts/roleplay.md"},u={id:"角色扮演类模板",tabindex:"-1"};function d(g,s,h,q,b,k){const p=e("DifficultyBadge");return t(),o("div",null,[n("h1",u,[s[0]||(s[0]=a("角色扮演类模板 ",-1)),i(p,{level:"beginner"}),s[1]||(s[1]=a()),s[2]||(s[2]=n("a",{class:"header-anchor",href:"#角色扮演类模板","aria-label":'Permalink to "角色扮演类模板 <DifficultyBadge level="beginner" />"'},"​",-1))]),s[3]||(s[3]=r(`<p>角色扮演是让 AI 输出质量跃升的最有效技巧之一。当你给 AI 一个具体角色，它就会自动调用该角色相关的知识、语气和思维模式。以下四个模板覆盖了常见的高价值角色扮演场景。</p><hr><h2 id="模板一-面试模拟" tabindex="-1">模板一：面试模拟 <a class="header-anchor" href="#模板一-面试模拟" aria-label="Permalink to &quot;模板一：面试模拟&quot;">​</a></h2><p><strong>场景说明</strong>：让 AI 扮演面试官，对你进行模拟面试，帮助你发现知识盲区和表达问题。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 角色设定</span></span>
<span class="line"><span>你是一位经验丰富的 [岗位名称] 面试官，在 [公司类型] 工作了 10 年，面试过 500+ 候选人。</span></span>
<span class="line"><span>你的面试风格是：先问基础知识，再逐步深入，遇到卡壳会给引导，最后给出总体评价。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 面试信息</span></span>
<span class="line"><span>- 岗位：[如&quot;前端开发工程师，中级&quot;]</span></span>
<span class="line"><span>- 公司类型：[如&quot;互联网中厂&quot;]</span></span>
<span class="line"><span>- 面试时长：约 20 分钟（5-6 个问题）</span></span>
<span class="line"><span>- 我的水平：[如&quot;2 年前端经验，熟悉 React&quot;]</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 流程</span></span>
<span class="line"><span>1. 你先做自我介绍（面试官视角），简要说明面试流程</span></span>
<span class="line"><span>2. 每次问一个问题，等我回答完再追问或进入下一个问题</span></span>
<span class="line"><span>3. 如果我的回答不完整，给一个提示让我补充</span></span>
<span class="line"><span>4. 面试结束后，给出：</span></span>
<span class="line"><span>   - 总体评分（1-10 分）</span></span>
<span class="line"><span>   - 我回答得好的地方</span></span>
<span class="line"><span>   - 我需要加强的知识点</span></span>
<span class="line"><span>   - 推荐的复习方向</span></span>
<span class="line"><span></span></span>
<span class="line"><span>现在开始。</span></span></code></pre></div><p><strong>示例对话</strong>：</p><blockquote><p><strong>AI（面试官）</strong>：好的，我是今天的面官张工。这次面试大概 20 分钟，我会先问几个前端基础知识，然后聊一聊你的项目经验。第一个问题：请解释一下 React 中的虚拟 DOM 是什么，它解决了什么问题？</p><p><strong>你</strong>：[回答……]</p><p><strong>AI（面试官）</strong>：理解不错。追问一下：虚拟 DOM 的 diff 算法大致是什么思路？你能描述一下 key 属性在其中的作用吗？</p></blockquote><p><strong>使用技巧</strong>：</p><ul><li>可以指定面试官的性格：温和型、压力型、技术深挖型</li><li>面试结束后，追加请求：<code>请把刚才我回答最薄弱的问题，用标准答案重新回答一遍</code></li><li>模拟多轮面试：第一轮基础面 → 第二轮技术深挖 → 第三轮 HR 面</li></ul><hr><h2 id="模板二-场景对话" tabindex="-1">模板二：场景对话 <a class="header-anchor" href="#模板二-场景对话" aria-label="Permalink to &quot;模板二：场景对话&quot;">​</a></h2><p><strong>场景说明</strong>：模拟真实的职场/商业对话场景，用于练习沟通、谈判、客服等软技能。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 角色设定</span></span>
<span class="line"><span>你现在扮演一位 [角色描述，如&quot;挑剔的客户/难沟通的同事/资深供应商&quot;]。</span></span>
<span class="line"><span>你的性格特点是 [如&quot;急躁、注重细节、但通情达理&quot;]。</span></span>
<span class="line"><span>你的目标是 [如&quot;拿到最低价/推动项目尽快上线&quot;]。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 我的角色</span></span>
<span class="line"><span>我是 [你的角色，如&quot;新入职的客户经理/项目负责人&quot;]。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 场景</span></span>
<span class="line"><span>[描述具体场景，如&quot;客户投诉产品故障，要求赔偿和紧急修复&quot;]</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 规则</span></span>
<span class="line"><span>1. 你先开口，以角色身份发起对话</span></span>
<span class="line"><span>2. 每次回复后等待我的回应，再继续推进</span></span>
<span class="line"><span>3. 根据我的应对方式调整你的态度（如果我处理得当，你会缓和；如果我说错话，你会更生气）</span></span>
<span class="line"><span>4. 对话结束后，给出复盘：我做得好的地方 + 我可以改进的地方</span></span>
<span class="line"><span></span></span>
<span class="line"><span>开始。</span></span></code></pre></div><p><strong>示例对话</strong>：</p><blockquote><p><strong>AI（客户）</strong>：喂，你们这系统怎么回事？从下午两点开始就登录不了，我们这边十几个员工都在干等！你们到底有没有人管？</p><p><strong>你</strong>：[回应……]</p><p><strong>AI（客户）</strong>：现在修复？修复要多久？我告诉你，上个月也出现过一次类似情况，你们当时保证不会再发生的……</p></blockquote><p><strong>使用技巧</strong>：</p><ul><li>这个模板的关键是给 AI 充分的角色细节——性格、目标、情绪状态</li><li>可以在对话中加入&quot;突发事件&quot;增加难度：<code>在第 3 轮对话时，客户突然提出一个新的投诉</code></li><li>适合反复练习同一个场景，每次调整自己的策略看 AI 的不同反应</li></ul><hr><h2 id="模板三-头脑风暴伙伴" tabindex="-1">模板三：头脑风暴伙伴 <a class="header-anchor" href="#模板三-头脑风暴伙伴" aria-label="Permalink to &quot;模板三：头脑风暴伙伴&quot;">​</a></h2><p><strong>场景说明</strong>：给 AI 设定一个专业角色，让它以特定视角与你一起发散思考、碰撞想法。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 角色设定</span></span>
<span class="line"><span>你现在是 [角色，如&quot;一位在消费品行业有 15 年经验的产品经理&quot;]。</span></span>
<span class="line"><span>你的思维特点是：善于发现用户痛点、注重视觉与交互体验、习惯从数据中找方向。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 我们的目标</span></span>
<span class="line"><span>[如&quot;为一款面向年轻人的咖啡品牌策划营销方案&quot;]</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 头脑风暴规则</span></span>
<span class="line"><span>1. 你先提出 3 个方向性思路（不要太具体），让我选择感兴趣的方向</span></span>
<span class="line"><span>2. 我选择后，我们对这个方向进行深度展开</span></span>
<span class="line"><span>3. 你可以质疑我的想法，但要给出建设性的替代方案</span></span>
<span class="line"><span>4. 鼓励天马行空的创意，不要过早否定</span></span>
<span class="line"><span></span></span>
<span class="line"><span>开始。</span></span></code></pre></div><p><strong>示例对话</strong>：</p><blockquote><p><strong>AI</strong>：基于你提到的年轻人咖啡品牌，我想到三个方向：</p><ol><li><strong>场景切入</strong>——围绕&quot;独处时刻&quot;做内容，把咖啡变成一种仪式感</li><li><strong>社交货币</strong>——让产品本身成为分享素材，比如文创联名包装</li><li><strong>技术卖点</strong>——主打工艺差异，比如&quot;鲜烘七天&quot;的供应链故事</li></ol><p>你对哪个方向更感兴趣？或者你想融合哪两个？</p></blockquote><p><strong>使用技巧</strong>：</p><ul><li>角色设定的专业程度直接影响 brainstorm 的质量——越具体越好</li><li>可以给 AI 一个&quot;反向角色&quot;让它扮演批评者：<code>在我想法成型后，请你切换为保守派 CFO 的视角来挑刺</code></li><li>适合作为思考的&quot;启动器&quot;，AI 给种子想法，你来延伸和判断</li></ul><hr><h2 id="模板四-代码评审" tabindex="-1">模板四：代码评审 <a class="header-anchor" href="#模板四-代码评审" aria-label="Permalink to &quot;模板四：代码评审&quot;">​</a></h2><p><strong>场景说明</strong>：让 AI 扮演资深工程师，对你的代码进行专业评审，从可读性、性能、安全等维度给出建议。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 角色设定</span></span>
<span class="line"><span>你是一位有 12 年经验的资深后端工程师，目前在某大型互联网公司负责代码质量审核。</span></span>
<span class="line"><span>你的评审风格是：严格但建设性，会解释&quot;为什么不好&quot;而不仅仅是&quot;哪里不好&quot;。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 评审要求</span></span>
<span class="line"><span>请从以下维度评审我的代码：</span></span>
<span class="line"><span>1. **可读性**：命名、注释、结构是否清晰</span></span>
<span class="line"><span>2. **性能**：是否有明显的性能问题或优化空间</span></span>
<span class="line"><span>3. **安全性**：是否有安全漏洞（如注入、越权、敏感信息泄露）</span></span>
<span class="line"><span>4. **最佳实践**：是否遵循了该语言的社区最佳实践</span></span>
<span class="line"><span>5. **边界处理**：是否处理了异常、空值、边界情况</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 输出格式</span></span>
<span class="line"><span>- 逐条列出问题，每条标注严重程度：🔴严重 / 🟡建议 / 🟢小优化</span></span>
<span class="line"><span>- 给出修改后的代码示例</span></span>
<span class="line"><span>- 最后总结：3 个最重要的改进点</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 我的代码</span></span>
<span class="line"><span>[粘贴你的代码]</span></span></code></pre></div><p><strong>示例对话</strong>：</p><blockquote><p><strong>AI</strong>：</p><h3 id="🔴-严重-1-条" tabindex="-1">🔴 严重（1 条） <a class="header-anchor" href="#🔴-严重-1-条" aria-label="Permalink to &quot;🔴 严重（1 条）&quot;">​</a></h3><ol><li><strong>SQL 注入风险</strong>（第 12 行） <code>query = f&quot;SELECT * FROM users WHERE name = &#39;{user_input}&#39;&quot;</code> 直接拼接用户输入，存在注入风险。 <strong>修改建议</strong>：使用参数化查询<div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cursor.execute(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;SELECT * FROM users WHERE name = ?&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, (user_input,))</span></span></code></pre></div></li></ol><h3 id="🟡-建议-3-条" tabindex="-1">🟡 建议（3 条） <a class="header-anchor" href="#🟡-建议-3-条" aria-label="Permalink to &quot;🟡 建议（3 条）&quot;">​</a></h3><ol start="2"><li><strong>N+1 查询问题</strong>（第 25 行）……（持续）</li></ol></blockquote><p><strong>使用技巧</strong>：</p><ul><li>可以指定评审的语言和框架，AI 会给出更针对性的建议</li><li>如果想重点关注某个维度，调高它的优先级：<code>请把安全性作为最重要的评审维度</code></li><li>评审完后可以追问：<code>请根据你的建议，帮我重写这份代码</code></li></ul><hr><h2 id="角色扮演类-prompt-通用原则" tabindex="-1">角色扮演类 Prompt 通用原则 <a class="header-anchor" href="#角色扮演类-prompt-通用原则" aria-label="Permalink to &quot;角色扮演类 Prompt 通用原则&quot;">​</a></h2><ol><li><strong>角色描述要具体</strong>——&quot;你是一个程序员&quot;远不如&quot;你是一个在 Google 工作 8 年的 Go 语言后端工程师&quot;</li><li><strong>给角色加上性格和偏好</strong>——这让交互更真实、更有针对性</li><li><strong>设置交互规则</strong>——是一问一答、还是对话轮次、还是 AI 主动推进</li><li><strong>要求复盘</strong>——角色扮演结束后，让 AI 切换回&quot;教练&quot;模式，给出反馈</li><li><strong>反复练习</strong>——同一个场景，用不同的应对策略，看 AI 的不同反应</li></ol>`,36))])}const f=l(c,[["render",d]]);export{v as __pageData,f as default};
